<script setup>
import { computed, onMounted, reactive, ref } from 'vue'
import AppIcon from '@/components/AppIcon.vue'
import { createVideo, deleteVideo, deleteVideos, getVideo, getVideoOverview, getVideoPlayUrl, getVideos, updateVideo, updateVideoStatus, uploadVideoAsset } from '@/services/video'

const rows=ref([]),overview=ref(null),loading=ref(true),selected=ref(new Set()),busyIds=ref(new Set()),openMenu=ref(null),message=ref(null)
const query=reactive({keyword:'',status:'',uploadedFrom:'',uploadedTo:'',sortOrder:'desc',page:1,size:10})
const pager=reactive({total:0,pages:1})
const form=reactive({open:false,mode:'create',loading:false,uploadingVideo:false,uploadingCover:false,id:null,title:'',description:'',videoUrl:null,originalName:null,coverUrl:null,duration:null,fileSize:null,allowDrag:false,allowSpeed:true,allowCache:true,status:'DRAFT'})
const preview=reactive({open:false,loading:false,title:'',url:''})
const confirmBox=reactive({open:false,title:'',content:'',action:null,loading:false})
const allSelected=computed(()=>rows.value.length>0&&rows.value.every(row=>selected.value.has(row.id)))
const metrics=computed(()=>[
  {label:'视频总数',value:overview.value?.totalVideos,rate:overview.value?.monthOverMonth?.totalVideosRate,icon:'▶',tone:'green'},
  {label:'存储占用',value:overview.value?.storageText||formatSize(overview.value?.storageBytes),rate:overview.value?.monthOverMonth?.storageRate,icon:'●',tone:'lime'},
  {label:'已发布',value:overview.value?.publishedVideos,rate:overview.value?.monthOverMonth?.publishedVideosRate,icon:'✓',tone:'teal'},
  {label:'草稿',value:overview.value?.draftVideos,rate:overview.value?.monthOverMonth?.draftVideosRate,icon:'✎',tone:'orange'},
])
const pageNumbers=computed(()=>pager.pages<=7?Array.from({length:pager.pages},(_,i)=>i+1):[...new Set([1,pager.pages,query.page-1,query.page,query.page+1])].filter(v=>v>0&&v<=pager.pages).sort((a,b)=>a-b))

function toast(text,type='success'){message.value={text,type};window.setTimeout(()=>message.value=null,2600)}
function number(value){return Number(value||0).toLocaleString('zh-CN')}
function formatSize(bytes){const value=Number(bytes||0);if(!value)return '0 B';if(value>=1073741824)return `${(value/1073741824).toFixed(1)} GB`;if(value>=1048576)return `${(value/1048576).toFixed(1)} MB`;return `${(value/1024).toFixed(1)} KB`}
function fileSize(row){return row.fileSizeText||formatSize(row.fileSize)}
function date(value){if(!value)return '—';const d=new Date(value);return Number.isNaN(d.getTime())?value:new Intl.DateTimeFormat('zh-CN',{year:'numeric',month:'2-digit',day:'2-digit',hour:'2-digit',minute:'2-digit',hour12:false}).format(d).replaceAll('/','-')}
function statusLabel(status){return {DRAFT:'草稿',PUBLISHED:'已发布',OFFLINE:'已下架'}[status]||status}
async function loadList(){loading.value=true;try{const data=await getVideos(query);rows.value=data?.records||[];pager.total=data?.total||0;pager.pages=data?.pages||1;if(query.page>pager.pages){query.page=pager.pages;return loadList()}}catch(error){toast(error.message,'error')}finally{loading.value=false}}
async function loadOverview(){try{overview.value=await getVideoOverview()}catch(error){toast(error.message,'error')}}
async function refresh(){selected.value=new Set();openMenu.value=null;await Promise.all([loadList(),loadOverview()])}
function search(){query.page=1;selected.value=new Set();loadList()}
function reset(){Object.assign(query,{keyword:'',status:'',uploadedFrom:'',uploadedTo:'',sortOrder:'desc',page:1});loadList()}
function goPage(page){if(page<1||page>pager.pages||page===query.page)return;query.page=page;selected.value=new Set();loadList()}
function toggleOne(id){const next=new Set(selected.value);next.has(id)?next.delete(id):next.add(id);selected.value=next}
function toggleAll(){selected.value=allSelected.value?new Set():new Set(rows.value.map(row=>row.id))}
function clearForm(){Object.assign(form,{loading:false,uploadingVideo:false,uploadingCover:false,id:null,title:'',description:'',videoUrl:null,originalName:null,coverUrl:null,duration:null,fileSize:null,allowDrag:false,allowSpeed:true,allowCache:true,status:'DRAFT'})}
function openUpload(){clearForm();form.mode='create';form.open=true}
async function openEdit(row){clearForm();form.mode='edit';form.open=true;form.loading=true;form.id=row.id;openMenu.value=null;try{const detail=await getVideo(row.id);Object.assign(form,detail,{description:detail.description||'',allowDrag:Boolean(detail.allowDrag),allowSpeed:Boolean(detail.allowSpeed),allowCache:Boolean(detail.allowCache)})}catch(error){form.open=false;toast(error.message,'error')}finally{form.loading=false}}
function readDuration(file){return new Promise((resolve,reject)=>{const video=document.createElement('video');const url=URL.createObjectURL(file);video.preload='metadata';video.onloadedmetadata=()=>{const seconds=Math.round(video.duration);URL.revokeObjectURL(url);Number.isFinite(seconds)&&seconds>0?resolve(seconds):reject(new Error())};video.onerror=()=>{URL.revokeObjectURL(url);reject(new Error())};video.src=url})}
async function chooseVideo(file){if(!file)return;if(!/\.mp4$/i.test(file.name)||file.type!=='video/mp4')return toast('仅支持 MP4 视频','error');form.uploadingVideo=true;try{form.duration=await readDuration(file);const result=await uploadVideoAsset(file,'VIDEO_FILE');form.videoUrl=result.url;form.originalName=result.originalFileName;form.fileSize=result.size;if(!form.title)form.title=result.originalFileName.replace(/\.mp4$/i,'');toast('视频上传成功')}catch(error){toast(error.message||'无法读取视频元数据，请上传标准 H.264 + AAC MP4','error')}finally{form.uploadingVideo=false}}
async function chooseCover(file){if(!file)return;if(!['image/jpeg','image/png'].includes(file.type))return toast('封面仅支持 JPG、JPEG、PNG','error');if(file.size>2*1024*1024)return toast('封面不能超过 2 MB','error');form.uploadingCover=true;try{form.coverUrl=(await uploadVideoAsset(file,'VIDEO_COVER')).url;toast('封面上传成功')}catch(error){toast(error.message,'error')}finally{form.uploadingCover=false}}
async function save(targetStatus=null){if(form.loading)return;const title=form.title.trim();if(!title)return toast('请输入视频标题','error');if(title.length>200)return toast('标题不能超过 200 个字符','error');if(form.description.length>2000)return toast('简介不能超过 2000 个字符','error');if(form.mode==='create'&&(!form.videoUrl||!form.duration))return toast('请先上传有效 MP4 视频','error');form.loading=true;const common={title,description:form.description.trim()||null,coverUrl:form.coverUrl||null,allowDrag:Boolean(form.allowDrag),allowSpeed:Boolean(form.allowSpeed),allowCache:Boolean(form.allowCache)};try{if(form.mode==='create')await createVideo({...common,videoUrl:form.videoUrl,originalName:form.originalName,duration:form.duration,fileSize:form.fileSize,status:targetStatus||'DRAFT'});else await updateVideo(form.id,common);form.open=false;toast(form.mode==='create'?(targetStatus==='PUBLISHED'?'视频已发布':'视频已保存为草稿'):'视频已更新');await refresh()}catch(error){toast(error.message,'error')}finally{form.loading=false}}
async function showPreview(row){preview.open=true;preview.loading=true;preview.title=row.title;preview.url='';openMenu.value=null;try{preview.url=(await getVideoPlayUrl(row.id)).playUrl}catch(error){preview.open=false;toast(error.message,'error')}finally{preview.loading=false}}
function statuses(current){return current==='DRAFT'?['PUBLISHED']:current==='PUBLISHED'?['OFFLINE','DRAFT']:['PUBLISHED']}
async function changeStatus(row,status){openMenu.value=null;const next=new Set(busyIds.value);next.add(row.id);busyIds.value=next;try{await updateVideoStatus(row.id,status);toast(`视频已${statusLabel(status)}`);await refresh()}catch(error){toast(error.message,'error')}finally{const done=new Set(busyIds.value);done.delete(row.id);busyIds.value=done}}
function ask(title,content,action){Object.assign(confirmBox,{open:true,title,content,action,loading:false});openMenu.value=null}
async function confirmAction(){confirmBox.loading=true;try{await confirmBox.action?.();confirmBox.open=false}catch{}finally{confirmBox.loading=false}}
function removeOne(row){ask('删除视频',`确定删除“${row.title}”吗？已关联课程点的视频无法删除。`,async()=>{try{await deleteVideo(row.id);toast('视频已删除');await refresh()}catch(error){toast(error.message,'error');throw error}})}
function removeBatch(){const ids=[...selected.value];if(!ids.length)return toast('请先选择视频','error');ask('批量删除',`确定删除选中的 ${ids.length} 个视频吗？任一视频不满足条件时整批不删除。`,async()=>{try{const result=await deleteVideos(ids);toast(`已删除 ${result?.deletedCount??ids.length} 个视频`);await refresh()}catch(error){toast(error.message,'error');throw error}})}
onMounted(refresh)
</script>

<template>
  <section class="video-page" @click.self="openMenu=null">
    <div v-if="message" class="toast" :class="message.type">{{ message.text }}</div>
    <div class="metrics"><div v-for="item in metrics" :key="item.label" class="metric card"><i :class="item.tone">{{ item.icon }}</i><div><span>{{ item.label }}</span><strong>{{ typeof item.value==='number'?number(item.value):item.value||'0' }}</strong><small v-if="item.rate!==null&&item.rate!==undefined" :class="{down:item.rate<0}">较上月 {{ item.rate>=0?'↑':'↓' }} {{ Math.abs(item.rate) }}%</small></div></div></div>
    <div class="filters card"><label class="keyword"><input v-model="query.keyword" maxlength="100" placeholder="搜索视频标题、简介或上传者..." @keyup.enter="search"/><AppIcon name="search" :size="18"/></label><label>状态<select v-model="query.status"><option value="">全部状态</option><option value="DRAFT">草稿</option><option value="PUBLISHED">已发布</option><option value="OFFLINE">已下架</option></select></label><label class="dates">上传日期<input v-model="query.uploadedFrom" type="date"/><span>至</span><input v-model="query.uploadedTo" type="date"/></label><label>排序<select v-model="query.sortOrder"><option value="desc">从新到旧</option><option value="asc">从旧到新</option></select></label><button class="reset" @click="reset">重置</button><button class="search-btn" @click="search">查询</button><button class="batch" :disabled="!selected.size" @click="removeBatch">批量删除</button><button class="upload" @click="openUpload">↥ 上传视频</button></div>
    <div class="table-card card"><div class="table-scroll"><table><thead><tr><th><input type="checkbox" :checked="allSelected" @change="toggleAll"/></th><th>视频信息</th><th>时长</th><th>大小</th><th>上传者</th><th>上传时间</th><th>状态</th><th>操作</th></tr></thead><tbody v-if="!loading&&rows.length"><tr v-for="row in rows" :key="row.id"><td><input type="checkbox" :checked="selected.has(row.id)" @change="toggleOne(row.id)"/></td><td><div class="video-info"><div class="cover"><img v-if="row.coverUrl" :src="row.coverUrl" alt=""/><span>▶</span></div><div><strong>{{ row.title }}</strong><small>{{ row.description||'暂无简介' }}</small></div></div></td><td>{{ row.durationText||`${row.duration||0} 秒` }}</td><td>{{ fileSize(row) }}</td><td>{{ row.uploaderName||'未知用户' }}</td><td>{{ date(row.uploadedAt) }}</td><td><span class="status" :class="row.status.toLowerCase()">{{ statusLabel(row.status) }}</span></td><td><div class="actions"><button title="预览" @click="showPreview(row)">◉</button><button title="编辑" @click="openEdit(row)">✎</button><div class="more"><button title="更多" @click.stop="openMenu=openMenu===row.id?null:row.id">•••</button><div v-if="openMenu===row.id" class="menu"><button v-for="status in statuses(row.status)" :key="status" @click="changeStatus(row,status)">{{ statusLabel(status) }}</button><button class="danger-text" @click="removeOne(row)">删除</button></div></div></div></td></tr></tbody></table><div v-if="loading" class="state"><span class="loader"></span>正在加载视频...</div><div v-else-if="!rows.length" class="state">暂无符合条件的视频</div></div><footer><span>共 {{ number(pager.total) }} 条</span><nav><button :disabled="query.page===1" @click="goPage(query.page-1)">‹</button><template v-for="(page,index) in pageNumbers" :key="page"><i v-if="index&&page-pageNumbers[index-1]>1">…</i><button :class="{active:page===query.page}" @click="goPage(page)">{{ page }}</button></template><button :disabled="query.page===pager.pages" @click="goPage(query.page+1)">›</button></nav><select v-model="query.size" @change="query.page=1;loadList()"><option :value="10">10条/页</option><option :value="20">20条/页</option><option :value="50">50条/页</option></select></footer></div>
    <div v-if="form.open" class="overlay"><form class="dialog form-dialog" @submit.prevent="save()"><header><h2>{{ form.mode==='create'?'上传视频':'编辑视频' }}</h2><button type="button" @click="form.open=false">×</button></header><div class="form-body"><label v-if="form.mode==='create'" class="drop"><input type="file" accept="video/mp4,.mp4" @change="chooseVideo($event.target.files[0])"/><i>▶</i><strong>{{ form.uploadingVideo?'上传中...':form.originalName||'选择 MP4 视频' }}</strong><small v-if="form.duration">时长 {{ form.duration }} 秒 · {{ formatSize(form.fileSize) }}</small><small v-else>需使用 H.264 + AAC 编码</small></label><label>视频标题 <em>*</em><input v-model="form.title" maxlength="200"/></label><label>简介<textarea v-model="form.description" maxlength="2000"></textarea><small>{{ form.description.length }}/2000</small></label><label class="cover-upload">视频封面<input type="file" accept="image/jpeg,image/png" @change="chooseCover($event.target.files[0])"/><b>{{ form.uploadingCover?'上传中...':form.coverUrl?'点击替换封面':'选择 JPG/PNG（最大 2 MB）' }}</b><img v-if="form.coverUrl" :src="form.coverUrl" alt="封面预览"/></label><div class="settings"><label><input v-model="form.allowDrag" type="checkbox"/>允许拖拽进度</label><label><input v-model="form.allowSpeed" type="checkbox"/>允许倍速</label><label><input v-model="form.allowCache" type="checkbox"/>允许客户端缓存</label></div></div><footer><button type="button" class="cancel" @click="form.open=false">取消</button><button v-if="form.mode==='create'" type="button" class="draft" :disabled="form.loading||form.uploadingVideo||form.uploadingCover" @click="save('DRAFT')">保存草稿</button><button class="save" :disabled="form.loading||form.uploadingVideo||form.uploadingCover" @click="form.mode==='create'&&save('PUBLISHED')">{{ form.loading?'保存中...':form.mode==='create'?'直接发布':'保存修改' }}</button></footer></form></div>
    <div v-if="preview.open" class="overlay" @mousedown.self="preview.open=false"><div class="dialog preview-dialog"><header><h2>{{ preview.title }}</h2><button @click="preview.open=false">×</button></header><div class="player"><div v-if="preview.loading" class="state">正在获取播放地址...</div><video v-else :src="preview.url" controls autoplay playsinline></video></div></div></div>
    <div v-if="confirmBox.open" class="overlay"><div class="dialog confirm"><header><h2>{{ confirmBox.title }}</h2><button @click="confirmBox.open=false">×</button></header><div class="confirm-content"><i>!</i><p>{{ confirmBox.content }}</p></div><footer><button class="cancel" @click="confirmBox.open=false">取消</button><button class="danger" :disabled="confirmBox.loading" @click="confirmAction">{{ confirmBox.loading?'处理中...':'确定' }}</button></footer></div></div>
  </section>
</template>

<style scoped>
.video-page{min-height:calc(100vh - 79px);padding:20px;background:#f7f9f8;color:#29312d}.card{background:#fff;border:1px solid #e7ebe8;border-radius:14px;box-shadow:0 4px 14px rgba(17,62,42,.05)}.metrics{display:grid;grid-template-columns:repeat(4,1fr);gap:18px}.metric{min-height:126px;display:flex;align-items:center;gap:19px;padding:22px}.metric>i{width:58px;height:58px;display:grid;place-items:center;flex:none;color:#fff;border-radius:15px;font-size:24px;font-style:normal}.metric .green,.metric .teal{background:linear-gradient(135deg,#12a16a,#007446)}.metric .lime{background:linear-gradient(135deg,#a3dc2c,#64b90c)}.metric .orange{background:linear-gradient(135deg,#ffad23,#ff7b00)}.metric span,.metric strong,.metric small{display:block}.metric strong{margin:6px 0;font-size:26px}.metric small{color:#34995a;font-size:12px}.metric small.down{color:#e34a4a}.filters{display:flex;align-items:end;gap:12px;margin:18px 0;padding:20px}.filters>label:not(.keyword){display:flex;flex-direction:column;gap:7px;color:#5e6662;font-size:12px}.filters select,.filters input{height:39px;padding:0 10px;border:1px solid #dce2de;border-radius:7px;background:#fff}.keyword{width:230px;height:39px;display:flex;align-items:center;padding:0 12px;border:1px solid #dce2de;border-radius:7px}.keyword input{flex:1;min-width:0;padding:0;border:0;outline:0}.dates{flex-direction:row!important;align-items:center}.dates input{width:132px}.filters button{height:39px;padding:0 15px;border-radius:7px;cursor:pointer}.reset{margin-left:auto;border:1px solid #ddd;background:#fff}.search-btn,.upload{color:#fff;background:#087b45}.batch{color:#d74848;border:1px solid #eccaca;background:#fff}.batch:disabled{opacity:.45;cursor:not-allowed}.table-card{overflow:hidden}.table-scroll{overflow:auto}table{width:100%;min-width:1100px;border-collapse:collapse;font-size:13px}th{height:48px;background:#fbfcfb;text-align:left}td{height:88px;border-top:1px solid #e9edeb;color:#555d59}th:first-child,td:first-child{width:54px;padding-left:18px}th:nth-child(2){width:330px}th:nth-child(3){width:90px}th:nth-child(4){width:100px}th:nth-child(5){width:120px}th:nth-child(6){width:175px}th:nth-child(7){width:100px}input[type=checkbox]{accent-color:#16834e}.video-info{display:flex;align-items:center;gap:13px}.cover{position:relative;width:98px;height:58px;overflow:hidden;flex:none;background:linear-gradient(135deg,#d7ebe2,#aacabd);border-radius:7px}.cover img{width:100%;height:100%;object-fit:cover}.cover span{position:absolute;inset:0;display:grid;place-items:center;color:#fff;text-shadow:0 1px 4px #333}.video-info strong,.video-info small{display:block}.video-info strong{max-width:200px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;color:#232a26}.video-info small{max-width:210px;margin-top:7px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;color:#868d89}.status{display:inline-flex;padding:5px 11px;border-radius:6px;font-size:12px}.status.published{color:#43952d;background:#edf7e7}.status.draft{color:#e28720;background:#fff3e6}.status.offline{color:#d64a4a;background:#ffeded}.actions{display:flex;gap:8px}.actions>button,.more>button{width:32px;height:32px;border:1px solid #dfe4e1;border-radius:6px;background:#fff;cursor:pointer}.more{position:relative}.menu{position:absolute;z-index:5;right:0;top:36px;width:105px;padding:5px;background:#fff;border:1px solid #e0e4e2;border-radius:8px;box-shadow:0 8px 25px rgba(0,40,20,.14)}.menu button{width:100%;padding:8px 10px;text-align:left;background:none;border-radius:5px;cursor:pointer}.menu button:hover{background:#f1f7f3}.menu .danger-text{color:#dd4242}.state{height:250px;display:flex;align-items:center;justify-content:center;gap:10px;color:#8b938f}.loader{width:22px;height:22px;border:2px solid #d9e4dd;border-top-color:#26905a;border-radius:50%;animation:spin .7s linear infinite}@keyframes spin{to{transform:rotate(360deg)}}.table-card>footer{height:60px;display:flex;align-items:center;gap:22px;padding:0 20px;border-top:1px solid #edf0ee;font-size:13px}.table-card nav{display:flex;align-items:center;gap:7px;margin-left:auto}.table-card nav button{width:35px;height:35px;border:1px solid #e0e4e2;border-radius:6px;background:#fff;cursor:pointer}.table-card nav button.active{color:#fff;background:#168c3a}.table-card nav button:disabled{opacity:.4}.table-card nav i{font-style:normal}.table-card>footer select{height:35px;border:1px solid #dfe3e1;border-radius:6px}.toast{position:fixed;z-index:60;top:92px;left:50%;transform:translateX(-50%);padding:11px 20px;color:#fff;background:#238b57;border-radius:8px}.toast.error{background:#ce4e4e}.overlay{position:fixed;z-index:40;inset:0;display:grid;place-items:center;padding:20px;background:rgba(11,31,21,.42);backdrop-filter:blur(2px)}.dialog{width:min(560px,96vw);overflow:hidden;background:#fff;border-radius:14px;box-shadow:0 20px 60px rgba(0,35,20,.22)}.dialog>header{height:62px;display:flex;align-items:center;justify-content:space-between;padding:0 23px;border-bottom:1px solid #eaeeeb}.dialog h2{margin:0;font-size:19px}.dialog header button{font-size:25px;color:#727a76;background:none;cursor:pointer}.form-body{max-height:calc(92vh - 127px);padding:24px;overflow:auto}.form-body>label{display:block;margin-bottom:18px;font-size:13px;font-weight:600}.form-body>label>input:not([type=file]),.form-body textarea{width:100%;margin-top:8px;padding:10px 12px;border:1px solid #dce1de;border-radius:7px}.form-body textarea{height:82px;resize:vertical}.form-body label>small{float:right;color:#999;font-weight:400}.form-body em{color:#dc4040;font-style:normal}.drop{position:relative;display:flex!important;flex-direction:column;align-items:center;justify-content:center;height:130px;border:1px dashed #9dbdad;border-radius:9px;color:#288353}.drop input,.cover-upload input{position:absolute;inset:0;width:100%;height:100%;opacity:0;cursor:pointer}.drop i{font-size:28px;font-style:normal}.drop strong{margin:8px 0}.drop small{float:none!important}.cover-upload{position:relative;min-height:76px;padding:12px;border:1px dashed #b9cbc1;border-radius:8px}.cover-upload b{display:block;margin-top:10px;color:#278255;font-size:12px;font-weight:400}.cover-upload img{position:absolute;right:10px;bottom:8px;width:80px;height:54px;object-fit:cover;border-radius:5px}.settings{display:flex;gap:20px;flex-wrap:wrap;font-size:13px}.dialog>footer{height:65px;display:flex;align-items:center;justify-content:flex-end;gap:12px;padding:0 23px;background:#fafbfa}.dialog>footer button{height:38px;padding:0 22px;border-radius:7px;cursor:pointer}.cancel{border:1px solid #d7dcda;background:#fff}.draft{color:#23784b;border:1px solid #94bca5;background:#fff}.save{color:#fff;background:#248b55}.danger{color:#fff;background:#d84b4b}.preview-dialog{width:min(900px,96vw)}.player{padding:18px;background:#101512}.player video{display:block;width:100%;max-height:72vh}.confirm-content{display:flex;gap:15px;padding:28px}.confirm-content i{width:30px;height:30px;display:grid;place-items:center;flex:none;color:#fff;background:#ee9c24;border-radius:50%;font-style:normal}.confirm-content p{margin:4px 0;line-height:1.7}
@media(max-width:1200px){.metrics{grid-template-columns:1fr 1fr}.filters{flex-wrap:wrap}.reset{margin-left:0}}
@media(max-width:760px){.video-page{padding:10px}.metrics{gap:10px}.metric{min-height:105px;padding:14px}.metric>i{width:44px;height:44px}.keyword{width:100%}.dates{width:100%;flex-wrap:wrap}.filters>label:not(.keyword){flex:1}.upload{margin-left:auto}.table-card>footer{flex-wrap:wrap}.table-card nav{order:3;width:100%;margin:0;justify-content:center}}
</style>
